exports.seed = async function (knex) {
  for (const [code, langs] of Object.entries(CHARTS)) {
    const update = {};
    for (const [lang, f] of Object.entries(langs)) {
      update[`name_${lang}`] = f.name;
      update[`signifies_${lang}`] = f.signifies;
      update[`description_${lang}`] = f.description;
      update[`key_uses_${lang}`] = JSON.stringify(f.key_uses || []);
    }
    await knex('varga_charts').where({ code }).update(update);
  }
};
